<script setup>import{onMounted,reactive,ref}from'vue';import PageActions from'../../../components/admin/PageActions.vue';import AsyncState from'../../../components/admin/AsyncState.vue';import{useNotifications}from'../../../composables/useNotifications.js';import{statusLabel}from'../../../lib/statusLabels.js';import{userApi}from'../../../lib/userApi.js';const notifications=useNotifications(),rows=ref([]),loading=ref(false),error=ref(''),query=ref('');const form=reactive({username:'',name:'',role:'REVIEWER',initialPassword:''});async function load(){loading.value=true;try{const r=query.value?await userApi.search({query:query.value,page:0,size:100}):await userApi.list(0,100);rows.value=r.content||[]}catch(e){error.value=e.message}finally{loading.value=false}}async function create(){try{await userApi.create({...form});Object.keys(form).forEach(k=>form[k]=k==='role'?'REVIEWER':'');notifications.success('后台账号已创建');await load()}catch(e){error.value=e.message;notifications.error(e.message)}}async function disable(row){if(!confirm(`确认停用账号 ${row.username}？其活动会话将立即失效。`))return;try{await userApi.disable(row.id);notifications.success('账号已停用');await load()}catch(e){error.value=e.message;notifications.error(e.message)}}async function reset(row){const password=prompt(`为 ${row.username} 设置临时密码（至少8字符）`);if(!password)return;try{await userApi.resetPassword(row.id,password);notifications.success('密码已重置，用户下次登录必须修改密码');await load()}catch(e){error.value=e.message;notifications.error(e.message)}}onMounted(load)</script>
<template><section class="admin-page"><PageActions title="用户管理" description="管理员可创建管理员/审核员、停用账号和重置临时密码。"/><div class="business-grid"><form class="business-card business-form" @submit.prevent="create"><h3>创建后台账号</h3><label>登录账号<input v-model.trim="form.username" required/></label><label>姓名<input v-model.trim="form.name" required/></label><label>角色<select v-model="form.role"><option value="ADMIN">管理员</option><option value="REVIEWER">审核员</option></select></label><label>初始密码<input v-model="form.initialPassword" type="password" minlength="8" required/></label><button class="button-primary">创建</button></form><div class="business-card business-card-wide"><form class="business-inline" @submit.prevent="load"><input v-model.trim="query" placeholder="账号、姓名或内部 ID"/><button class="button-secondary">搜索</button></form><p v-if="error" class="business-error">{{error}}</p><AsyncState :loading="loading" :error="''" :empty="!rows.length"><div class="business-table-wrap"><table class="business-table"><thead><tr><th>内部 ID</th><th>姓名</th><th>账号</th><th>角色</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="r in rows" :key="r.id"><td>{{r.internalUserNo}}</td><td>{{r.name}}</td><td>{{r.username}}</td><td>{{statusLabel('role',r.role)}}</td><td>{{statusLabel('user',r.status)}}</td><td><button class="button-link" @click="reset(r)">重置密码</button><button v-if="r.status==='ACTIVE'" class="button-link is-danger" @click="disable(r)">停用</button></td></tr></tbody></table></div></AsyncState></div></div></section></template>
